package com.example.sharehandler

import android.content.ClipData
import android.content.ContentResolver
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.provider.OpenableColumns
import android.webkit.URLUtil
import androidx.appcompat.app.AppCompatActivity
import java.io.File
import java.io.FileOutputStream
import java.io.InputStream

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleShareIntent(intent)
        finish()
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        if (intent != null) {
            handleShareIntent(intent)
            finish()
        }
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> handleActionSend(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleActionSendMultiple(intent)
        }
    }

    private fun handleActionSend(intent: Intent) {
        val type = intent.type

        val uris = mutableListOf<Uri>()
        val texts = mutableListOf<String>()

        intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)?.let { uris += it }
        intent.clipData?.let { uris += extractUrisFromClipData(it) }

        intent.getStringExtra(Intent.EXTRA_TEXT)?.let { texts += it }
        intent.getCharSequenceExtra(Intent.EXTRA_TEXT)?.toString()?.let { if (it !in texts) texts += it }
        intent.getStringExtra(Intent.EXTRA_SUBJECT)?.let { if (it.isNotBlank()) texts += it }

        if (type != null && type.startsWith("image/")) {
            val imageUris = uris.ifEmpty { extractUrisFromText(texts) }
            processSharedImages(imageUris)
            return
        }

        val urlsFromText = extractUrlsFromText(texts)
        if (urlsFromText.isNotEmpty()) {
            processSharedUrls(urlsFromText)
            return
        }

        val imageUrisFromUris = uris.filter { isImageUri(it) }
        if (imageUrisFromUris.isNotEmpty()) {
            processSharedImages(imageUrisFromUris)
            return
        }

        val otherUris = uris.filterNot { isImageUri(it) }
        if (otherUris.isNotEmpty()) {
            processSharedFiles(otherUris)
        }
    }

    private fun handleActionSendMultiple(intent: Intent) {
        val type = intent.type

        val uris = mutableListOf<Uri>()
        intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.let { uris += it }
        intent.clipData?.let { uris += extractUrisFromClipData(it) }

        val texts = mutableListOf<String>()
        intent.getStringExtra(Intent.EXTRA_TEXT)?.let { texts += it }
        intent.getCharSequenceExtra(Intent.EXTRA_TEXT)?.toString()?.let { if (it !in texts) texts += it }

        if (type != null && type.startsWith("image/")) {
            processSharedImages(uris)
            return
        }

        val urlsFromText = extractUrlsFromText(texts)
        if (urlsFromText.isNotEmpty()) {
            processSharedUrls(urlsFromText)
            return
        }

        val imageUris = uris.filter { isImageUri(it) }
        if (imageUris.isNotEmpty()) {
            processSharedImages(imageUris)
            return
        }

        if (uris.isNotEmpty()) {
            processSharedFiles(uris)
        }
    }

    private fun extractUrisFromClipData(clipData: ClipData): List<Uri> {
        val out = ArrayList<Uri>(clipData.itemCount)
        for (i in 0 until clipData.itemCount) {
            val item = clipData.getItemAt(i)
            item.uri?.let { out += it }
            item.intent?.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)?.let { out += it }
            item.text?.toString()?.let { out += extractUrisFromText(listOf(it)) }
        }
        return out.distinct()
    }

    private fun extractUrisFromText(texts: List<String>): List<Uri> {
        val out = mutableListOf<Uri>()
        for (t in texts) {
            val trimmed = t.trim()
            if (trimmed.isEmpty()) continue
            val uri = runCatching { Uri.parse(trimmed) }.getOrNull() ?: continue
            if (uri.scheme == "content" || uri.scheme == "file") out += uri
        }
        return out.distinct()
    }

    private fun extractUrlsFromText(texts: List<String>): List<String> {
        val out = mutableListOf<String>()
        for (t in texts) {
            val s = t.trim()
            if (s.isEmpty()) continue
            if (URLUtil.isNetworkUrl(s)) out += s
        }
        return out.distinct()
    }

    private fun isImageUri(uri: Uri): Boolean {
        val mime = runCatching { contentResolver.getType(uri) }.getOrNull()
        return mime?.startsWith("image/") == true
    }

    private fun processSharedUrls(urls: List<String>) {
        for (url in urls) {
            // TODO: Replace with your app's URL handling logic
            // Example: enqueue for processing, save to DB, open in WebView, etc.
            android.util.Log.d("ShareReceiver", "Shared URL: $url")
        }
    }

    private fun processSharedImages(imageUris: List<Uri>) {
        for (uri in imageUris.distinct()) {
            // TODO: Replace with your app's image handling logic
            // Example: copy to app storage, upload, run ML, etc.
            val copied = copyUriToCache(uri)
            android.util.Log.d("ShareReceiver", "Shared Image URI: $uri copiedTo=${copied?.absolutePath}")
        }
    }

    private fun processSharedFiles(uris: List<Uri>) {
        for (uri in uris.distinct()) {
            // TODO: Replace with your app's generic file handling logic
            val copied = copyUriToCache(uri)
            android.util.Log.d("ShareReceiver", "Shared File URI: $uri copiedTo=${copied?.absolutePath}")
        }
    }

    private fun copyUriToCache(uri: Uri): File? {
        return try {
            val name = queryDisplayName(contentResolver, uri) ?: "shared_${System.currentTimeMillis()}"
            val safeName = name.replace(Regex("""[^\w.\- ]"""), "_")
            val outFile = File(cacheDir, safeName)
            contentResolver.openInputStream(uri)?.use { input ->
                FileOutputStream(outFile).use { output ->
                    input.copyTo(output)
                }
            } ?: return null
            outFile
        } catch (_: Throwable) {
            null
        }
    }

    private fun queryDisplayName(resolver: ContentResolver, uri: Uri): String? {
        return try {
            resolver.query(uri, arrayOf(OpenableColumns.DISPLAY_NAME), null, null, null)?.use { c ->
                if (c.moveToFirst()) c.getString(0) else null
            }
        } catch (_: Throwable) {
            null
        }
    }
}

